#include "SampleObserverComponent.h"
#include "nsServiceManagerUtils.h"
#include "nsString.h"
#include "mozilla/Services.h"

// Implementation of nsISupports for reference counting
NS_IMPL_ISUPPORTS(SampleObserverComponent, nsIObserverService)

// Factory constructor macro - generates the constructor function
// This is used by the component registration system to instantiate the component
NS_GENERIC_FACTORY_CONSTRUCTOR_INIT(SampleObserverComponent, Initialize)

// ============================================================================
// SampleObserverComponent Implementation
// ============================================================================

SampleObserverComponent::SampleObserverComponent()
    : mIsShuttingDown(false) {}

SampleObserverComponent::~SampleObserverComponent() {
  Shutdown();
}

nsresult SampleObserverComponent::Initialize() {
  // Get the global observer service
  mObserverService = mozilla::services::GetObserverService();
  if (!mObserverService) {
    return NS_ERROR_FAILURE;
  }

  return NS_OK;
}

void SampleObserverComponent::Shutdown() {
  if (mIsShuttingDown) {
    return;
  }

  mIsShuttingDown = true;
  mObserverService = nullptr;
}

// ============================================================================
// nsIObserverService Implementation

